  ('EXP-2026-003', 'Flow Cytometry - CD4/CD8 Ratio Analysis',                     'T. Nguyen',    '2026-04-26', ARRAY['SMP-2026-004'],                       'BD FACSCanto II (FC-019)',                 'AB-CD4-2026-040',           'completed', 'fail',             'Negative controls above 3.2% background threshold. Sample purity insufficient. See DEV-2026-002.'),
