  ('EXP-2026-005', 'qRT-PCR - Inflammatory Gene Panel in Colon Tissue',           'A. Patel',     '2026-04-25', ARRAY['SMP-2026-003'],                       'Bio-Rad CFX96 (PCR-007)',                 'SYBR-2026-004',             'completed', 'pass',             'ACTB/GAPDH normalization stable. IL-1B and TNFa upregulated 4-fold vs control.'),
