  ('EXP-2026-007', 'Immunofluorescence - NF-kB Nuclear Translocation',            'J. Martinez',  '2026-05-10', ARRAY['SMP-2026-007'],                       'Leica DMi8 Fluorescence Microscope (MSC-011)', 'DAPI-2026-001',        'completed', 'conditional-pass', 'Nuclear signal detected. Background staining elevated in 2 of 6 fields. Flagged for repeat before publication.'),
