INSERT INTO deviations (deviation_id, severity, category, description, immediate_action, corrective_action, owner, status, opened_date, closed_date, linked_sample_id, linked_run_id) VALUES
  ('DEV-2026-001', 'critical', 'environmental', '-80C Freezer A temperature excursion detected. Temperature rose to -62C for approximately 2 hours before alarm triggered.', 'All samples transferred to -80C Freezer B. Freezer A taken offline for repair.', 'Schedule preventive maintenance for all ultra-low freezers. Verify continuous monitoring alerts. Add secondary alarm escalation path.', 'Dr. R. Osei', 'in-review',  '2026-05-02', NULL,         NULL,          NULL),
  ('DEV-2026-002', 'high',     'protocol',      'Flow cytometry run EXP-2026-003 negative controls exceeded 3.2% background threshold. Results do not meet acceptance criteria.', 'Run invalidated. Samples quarantined pending re-evaluation.', 'Re-stain with fresh antibody lot. Verify instrument QC status before repeat run. Update SOP to include pre-run control acceptance criteria step.', 'T. Nguyen', 'open',       '2026-04-26', NULL,         'SMP-2026-004','EXP-2026-003'),
  ('DEV-2026-003', 'medium',   'reagent',       'FITC-conjugated secondary antibody lot FL-2026-018 showed fluorescence intensity 34% below lot certificate specification.', 'Lot quarantined. All experiments using this lot flagged for review.', 'Notify supplier and initiate lot replacement. Update incoming reagent QC protocol to include full titration before release.', 'A. Patel', 'in-review',  '2026-05-07', NULL,         NULL,          NULL),
  ('DEV-2026-004', 'low',      'protocol',      'SOP-FC-003 was not updated to revision 2.1 before experiment EXP-2026-003 commenced. Operator used outdated gating strategy from revision 2.0.', 'Experiment outcome assessed - gating difference did not materially affect data validity.', 'Require SOP version confirmation in run setup checklist. Conduct lab-wide SOP review cycle.', 'T. Nguyen', 'resolved',   '2026-04-22', '2026-04-25', NULL,          'EXP-2026-003'),
  ('DEV-2026-005', 'high',     'equipment',     'BD FACSCanto II (FC-019) showing laser alignment drift. CV on size beads increased from 2.1% to 6.8% over 3-week period.', 'Instrument flagged. All pending flow cytometry experiments rescheduled pending service.', 'Schedule BD field service. Add weekly alignment bead QC check to instrument log. Evaluate backup instrument availability.', 'Dr. R. Osei', 'in-review',  '2026-05-13', NULL,         NULL,          'EXP-2026-003'),
  ('DEV-2026-006', 'medium',   'equipment',     'BioTek Epoch2 plate reader CV exceeded 15% threshold across technical replicates during repeat quality check.', 'Run data flagged for statistical review. QC report filed.', 'Recalibrate plate reader. Inspect wash head for blockage. Schedule performance verification with manufacturer protocol.', 'J. Martinez', 'in-review',  '2026-05-10', NULL,         NULL,          'EXP-2026-001'),
  ('DEV-2026-007', 'low',      'protocol',      'Biological waste disposal log missing entries for April 29 and April 30. Two autoclave runs not recorded.', 'Disposal confirmed via facility log cross-reference. No safety risk identified.', 'Retrain team on documentation requirements. Add waste log review to weekly lab safety check.', 'A. Patel', 'resolved',   '2026-04-30', '2026-05-02', NULL,          NULL),
  ('DEV-2026-008', 'critical', 'environmental', 'iPSC-derived neuron culture (SMP-2026-009) showing visible cloudiness and pH shift. Microbial contamination suspected.', 'Culture quarantined immediately. Incubator CO2 filter replaced. BSC surfaces decontaminated.', 'Full mycoplasma and bacterial screen on all active cultures. Review airflow certification in BSC 1. Trace cell handling records for cross-contamination pathway.', 'Dr. L. Chen', 'open',       '2026-05-19', NULL,         'SMP-2026-009', NULL);
